mapper.select:
SELECT l.id AS id, l.title AS title, l.cover_image_url AS posterUrl, '' AS tag, COUNT(r.id) AS hotValue FROM lecture_table l LEFT JOIN registration_table r ON r.lecture_id = l.id AND r.deleted = 0 AND r.status <> 'cancelled'
INNER JOIN lecture_tag_table lt ON lt.lecture_id = l.id AND lt.deleted = 0 AND lt.tag_id = #{tagId}
WHERE l.deleted = 0 AND l.status = 'published' AND l.lecture_start_time >= NOW() GROUP BY l.id, l.title, l.cover_image_url ORDER BY hotValue DESC, l.create_time DESC LIMIT #{limit}
